<template>
    <div class="container">
        <HeaderView />
        <div v-if="post" class="article-container">
            <!-- 返回按鈕 -->
            <router-link to="/blog" class="back-link">← Back to Blog</router-link>

            <!-- 文章標頭 -->
            <div class="article-header">
                <div class="article-meta">
                    <span class="article-date">{{ post.date }}</span>
                    <span class="article-category">{{ post.category }}</span>
                </div>
                <h1 class="article-title">{{ post.title }}</h1>
                <p class="article-description">{{ post.description }}</p>
                <div class="article-tags">
                    <span v-for="tag in post.tags" :key="tag" class="tag">#{{ tag }}</span>
                </div>
            </div>

            <!-- 分隔線 -->
            <div class="divider"></div>

            <!-- 文章內容 -->
            <div class="article-body">
                <template v-for="(block, index) in post.content">
                    <h2 v-if="block.type === 'heading'" :key="'h-' + index" class="body-heading">
                        {{ block.text }}
                    </h2>
                    <p v-else-if="block.type === 'paragraph'" :key="'p-' + index" class="body-paragraph">
                        {{ block.text }}
                    </p>
                </template>
            </div>

            <!-- 底部導航 -->
            <div class="divider"></div>
            <div class="article-nav">
                <router-link v-if="prevPost" :to="'/blog/' + prevPost.id" class="nav-link prev">
                    <span class="nav-direction">← 上一篇</span>
                    <span class="nav-title">{{ prevPost.title }}</span>
                </router-link>
                <div v-else></div>
                <router-link v-if="nextPost" :to="'/blog/' + nextPost.id" class="nav-link next">
                    <span class="nav-direction">下一篇 →</span>
                    <span class="nav-title">{{ nextPost.title }}</span>
                </router-link>
            </div>
        </div>

        <!-- 找不到文章 -->
        <div v-else class="not-found">
            <p>找不到此文章</p>
            <router-link to="/blog" class="back-link">← 回到 Blog</router-link>
        </div>
    </div>
</template>

<script>
import HeaderView from './HeaderView.vue'
import { posts } from '@/data/posts'

export default {
    name: 'BlogDetailView',
    components: {
        HeaderView
    },
    computed: {
        post() {
            const id = parseInt(this.$route.params.id)
            return posts.find(p => p.id === id)
        },
        currentIndex() {
            return posts.findIndex(p => p.id === this.post?.id)
        },
        prevPost() {
            return this.currentIndex > 0 ? posts[this.currentIndex - 1] : null
        },
        nextPost() {
            return this.currentIndex < posts.length - 1 ? posts[this.currentIndex + 1] : null
        }
    },
    watch: {
        '$route.params.id'() {
            window.scrollTo(0, 0)
        }
    }
}
</script>

