<template>
    <div class="container">
        <HeaderView />
        <div class="blog-container">
            <!-- 標題區域 -->
            <div class="header-section">
                <h1 class="title">
                    My <span class="highlight">Blog</span>
                </h1>
                <p class="subtitle">
                    開發日誌與技術筆記，紀錄每一次的學習與成長
                </p>
            </div>

            <!-- 分類篩選 -->
            <div class="filter-section">
                <button
                    v-for="category in categories"
                    :key="category.id"
                    :class="['filter-btn', { active: activeFilter === category.id }]"
                    @click="activeFilter = category.id"
                >
                    {{ category.name }}
                </button>
            </div>

            <!-- 文章列表 -->
            <div class="blog-list">
                <router-link
                    v-for="(post, index) in filteredPosts"
                    :key="post.id"
                    :to="'/blog/' + post.id"
                    class="blog-card"
                    :style="{ animationDelay: `${index * 0.1}s` }"
                >
                    <div class="card-meta">
                        <span class="card-date">{{ post.date }}</span>
                        <span class="card-category-tag">{{ post.category }}</span>
                    </div>
                    <h2 class="card-title">{{ post.title }}</h2>
                    <p class="card-description">{{ post.description }}</p>
                    <div class="card-tags">
                        <span v-for="tag in post.tags" :key="tag" class="tag">
                            #{{ tag }}
                        </span>
                    </div>
                    <span class="read-more">閱讀全文 →</span>
                </router-link>
            </div>

            <!-- 空狀態 -->
            <div v-if="filteredPosts.length === 0" class="empty-state">
                <p>此分類暫無文章</p>
            </div>
        </div>
    </div>
</template>

<script>
import HeaderView from './HeaderView.vue'
import { posts } from '@/data/posts'

export default {
    name: 'BlogView',
    components: {
        HeaderView
    },
    data() {
        return {
            activeFilter: 'all',
            categories: [
                { id: 'all', name: 'All' },
                { id: 'ios', name: 'iOS' },
                { id: 'web', name: 'Web' },
                { id: 'life', name: 'Life' }
            ],
            posts
        }
    },
    computed: {
        filteredPosts() {
            if (this.activeFilter === 'all') {
                return this.posts
            }
            return this.posts.filter(p => p.category === this.activeFilter)
        }
    }
}
</script>

